package main

import (
	"html/template"
	"log"
	"net/http"
	"sync"
	"time"
)

type Comment struct {
	Author  string
	Created time.Time
	HTML    template.HTML
}

type PageData struct {
	Title    string
	Comments []Comment
}

var (
	mu sync.RWMutex

	comments = []Comment{
		{
			Author:  "Alice",
			Created: time.Now().Add(-2 * time.Hour),
			HTML:    template.HTML(`<p>Hello! <b>Welcome</b> to the site.</p>`),
		},
		{
			Author:  "Bob",
			Created: time.Now().Add(-45 * time.Minute),
			HTML:    template.HTML(`<p>I like <i>basic formatting</i> and <a href="https://example.com">links</a>.</p>`),
		},
	}

	pageTmpl = template.Must(template.New("page").Funcs(template.FuncMap{
		"formatTime": func(t time.Time) string {
			return t.Format("2006-01-02 15:04")
		},
	}).Parse(`<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>{{.Title}}</title>
  <style>
    body { font-family: system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif; margin: 2rem; line-height: 1.4; }
    h1 { margin: 0 0 1rem 0; }
    .comment { border: 1px solid #ddd; border-radius: 8px; padding: 1rem; margin: 0 0 1rem 0; }
    .meta { color: #555; font-size: 0.9rem; margin: 0 0 0.5rem 0; }
    .meta .author { font-weight: 600; color: #222; }
    .content p { margin: 0.5rem 0; }
    a { color: #0b57d0; }
    code, pre { background: #f6f8fa; padding: 0.1rem 0.25rem; border-radius: 4px; }
  </style>
</head>
<body>
  <h1>{{.Title}}</h1>

  {{if .Comments}}
    {{range .Comments}}
      <div class="comment">
        <div class="meta">
          <span class="author">{{.Author}}</span>
          <span> · {{formatTime .Created}}</span>
        </div>
        <div class="content">{{.HTML}}</div>
      </div>
    {{end}}
  {{else}}
    <p>No comments yet.</p>
  {{end}}
</body>
</html>`))
)

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	mu.RLock()
	data := PageData{
		Title:    "User Comments",
		Comments: append([]Comment(nil), comments...),
	}
	mu.RUnlock()

	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := pageTmpl.Execute(w, data); err != nil {
		http.Error(w, "template error", http.StatusInternalServerError)
		return
	}
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/comments", commentsHandler)

	log.Println("listening on http://localhost:8080/comments")
	log.Fatal(http.ListenAndServe(":8080", mux))
}